 @classmethod
    def from_mongo(cls, data: Dict[str, Any]) -> 'Document':
        """
        Convert a MongoDB document to a Document instance.
        This ensures the MongoDB '_id' field is mapped to 'id'.
        """
        if '_id' in data:
            data['id'] = data.pop('_id')
        return cls(**data)
